const https = require('https');
const fs = require('fs');
const { execSync } = require('child_process');

function download(url, dest) {
  return new Promise((resolve, reject) => {
    https.get(url, (response) => {
      if (response.statusCode === 301 || response.statusCode === 302) {
        download(response.headers.location, dest).then(resolve).catch(reject);
        return;
      }
      const file = fs.createWriteStream(dest);
      response.pipe(file);
      file.on('finish', () => { file.close(); resolve(); });
    }).on('error', reject);
  });
}

async function main() {
  console.log('Downloading .NET install script...');
  await download('https://dot.net/v1/dotnet-install.sh', 'dotnet-install-script.sh');
  fs.chmodSync('dotnet-install-script.sh', 0o755);
  console.log('Installing .NET 10 SDK...');
  execSync('./dotnet-install-script.sh --channel 10.0 --install-dir /home/passp/.dotnet', { stdio: 'inherit' });
  console.log('Done!');
  execSync('/home/passp/.dotnet/dotnet --version', { stdio: 'inherit' });
}

main().catch(console.error);

